app.get('/login', (req, res) => {
  const state = randomString(16);
  const nonce = randomString(16);

  req.session.oidc = { state, nonce };

  const params = querystring.stringify({
    response_type: 'code',
    client_id: CLIENT_ID,
    redirect_uri: REDIRECT_URI,
    scope: SCOPE,
    state,
    nonce
  });

  res.redirect(`${AUTHORIZATION_ENDPOINT}?${params}`);
});

app.get('/callback', async (req, res) => {
  const { code, state } = req.query;

  if (!code || !state) {
    return res.status(400).json({ error: 'Missing code or state' });
  }

  if (!req.session.oidc || state !== req.session.oidc.state) {
    return res.status(400).json({ error: 'Invalid state' });
  }

  try {
    const tokenResponse = await axios.post(
      TOKEN_ENDPOINT,
      querystring.stringify({
        grant_type: 'authorization_code',
        code,
        redirect_uri: REDIRECT_URI,
        client_id: CLIENT_ID,
        client_secret: CLIENT_SECRET
      }),
      {
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded'
        }
      }
    );

    const tokens = tokenResponse.data;

    if (!tokens.id_token) {
      return res.status(400).json({ error: 'Missing id_token in token response' });
    }

    const decoded = jwt.decode(tokens.id_token);

    if (!decoded) {
      return res.status(400).json({ error: 'Unable to decode id_token' });
    }

    req.session.user = {
      sub: decoded.sub || null,
      email: decoded.email || null,
      name: decoded.name || null
    };

    req.session.tokens = {
      access_token: tokens.access_token || null,
      id_token: tokens.id_token || null,
      refresh_token: tokens.refresh_token || null,
      token_type: tokens.token_type || null,
      expires_in: tokens.expires_in || null
    };

    delete req.session.oidc;

    res.redirect('/profile');
  } catch (error) {
    const details =
      error.response && error.response.data ? error.response.data : error.message;
    res.status(500).json({ error: 'Token exchange failed', details });
  }
});

app.get('/profile', (req, res) => {
  if (!req.session.user) {
    return res.status(401).json({ error: 'Not authenticated' });
  }

  res.json({
    user: req.session.user,
    session: {
      authenticated: true
    }
  });
});

app.get('/logout', (req, res) => {
  req.session.destroy(() => {
    res.redirect('/');
  });
});

